body.script:
//
// Shortcuts management
var quoteScript = function() {
  var quoteText = document.getElementById('quote-text');
  var quoteSource = document.getElementById('quote-source');
  var quotes = [
    { text: 'get better wifi bro if it doesnt load', source: 'zaka' },
    { text: '69 is better then 67 imo', source: 'zaka' },
    { text: '404 Quote Not Found', source: '404.html and caddy' },
    { text: 'join the discord at https://discord.gg/4MpkuhG3R', source: 'zaka' },
    { text: 'h is better then e btw', source: 'your mom' }
  ];
  var quoteIndex = 0;

  window.setInterval(function() {
    quoteText.style.opacity = '0';
    quoteSource.style.opacity = '0';
    window.setTimeout(function() {
      quoteIndex = (quoteIndex + 1) % quotes.length;
      quoteText.textContent = quotes[quoteIndex].text;
      quoteSource.textContent = quotes[quoteIndex].source;
      quoteText.style.opacity = '1';
      quoteSource.style.opacity = '1';
    }, 350);
  }, 6000);
};

// Shortcuts management
var shortcutScript = function() {
  var shortcuts = [];
  var editingIndex = -1;
  var container = document.getElementById('shortcuts-container');
  var modal = document.getElementById('shortcut-modal');
  var labelInput = document.getElementById('shortcut-label-input');
  var urlInput = document.getElementById('shortcut-url-input');
  var imgInput = document.getElementById('shortcut-img-input');

  var defaultShortcuts = [
    { label: 'Google', url: 'https://www.google.com', img: 'https://cdn.jsdelivr.net/gh/zaka13alt/history@HEAD/images/google.svg' },
    { label: 'Games', url: 'https://zaka.qzz.io/games.html', img: 'data:image/svg+xml,%3Csvg xmlns=%27http://www.w3.org/2000/svg%27 width=%2740%27 height=%2740%27 viewBox=%270 0 40 40%27%3E%3Crect width=%2740%27 height=%2740%27 fill=%27%231a1a2e%27 rx=%278%27/%3E%3Ctext x=%2720%27 y=%2724%27 text-anchor=%27middle%27 fill=%27%2335D07F%27 font-size=%2714%27 font-family=%27Arial%27 font-weight=%27bold%27%3EG%3C/text%3E%3C/svg%3E' },
    { label: 'YouTube', url: 'https://www.youtube.com', img: 'https://cdn.jsdelivr.net/gh/zaka13alt/history@HEAD/images/yt.svg' },
    { label: 'GitHub', url: 'https://github.com', img: '' },
    { label: 'Reddit', url: 'https://www.reddit.com', img: '' },
    { label: 'AI', url: 'https://zaka.qzz.io/ai.html', img: 'data:image/svg+xml,%3Csvg xmlns=%27http://www.w3.org/2000/svg%27 width=%2740%27 height=%2740%27 viewBox=%270 0 40 40%27%3E%3Crect width=%2740%27 height=%2740%27 fill=%27%231a1a2e%27 rx=%278%27/%3E%3Ctext x=%2720%27 y=%2724%27 text-anchor=%27middle%27 fill=%27%2335D07F%27 font-size=%2714%27 font-family=%27Arial%27 font-weight=%27bold%27%3EAI%3C/text%3E%3C/svg%3E' }

  ];

  function loadShortcuts() {
    try {
      var saved = localStorage.getItem('zaka13_shortcuts');
      if (saved) {
        shortcuts = JSON.parse(saved);
        if (shortcuts[4] && shortcuts[4].label === 'Games') {
          shortcuts[4] = defaultShortcuts[5];
        }
        if (shortcuts.length === 5 && shortcuts[0] && shortcuts[0].label === 'Google' && shortcuts[1] && shortcuts[1].label === 'YouTube') {
          shortcuts.splice(1, 0, defaultShortcuts[1]);
        }
      } else {
        shortcuts = defaultShortcuts.map(function(s) { return { label: s.label, url: s.url, img: s.img }; });
      }
    } catch (e) {
      shortcuts = defaultShortcuts.map(function(s) { return { label: s.label, url: s.url, img: s.img }; });
    }
    renderShortcuts();
  }

  function saveShortcutsData() {
    try {
      localStorage.setItem('zaka13_shortcuts', JSON.stringify(shortcuts));
    } catch (e) {}
  }

  function renderShortcuts() {
    var btns = container.querySelectorAll('.shortcut-btn');
    btns.forEach(function(btn, index) {
      if (index < shortcuts.length) {
        var data = shortcuts[index];
        var img = btn.querySelector('img');
        var label = btn.querySelector('.shortcut-label');
        if (img) img.src = data.img || defaultShortcuts[index]?.img || '';
        if (label) label.textContent = data.label || 'Shortcut ' + (index + 1);
        btn.dataset.url = data.url || '';
        btn.onclick = function(e) {
          e.preventDefault();
          var url = this.dataset.url;
          if (url) {
            navigateTo(url);
          } else {
            editShortcut(index);
          }
        };
        btn.ondblclick = function(e) {
          e.preventDefault();
          var idx = parseInt(this.dataset.index);
          editShortcut(idx);
        };
      }
    });
  }

  window.editShortcut = function(index) {
    editingIndex = index;
    var data = shortcuts[index] || { label: '', url: '', img: '' };
    labelInput.value = data.label || '';
    urlInput.value = data.url || '';
    imgInput.value = data.img || '';
    modal.classList.add('active');
  };

  window.closeModal = function() {
    modal.classList.remove('active');
    editingIndex = -1;
  };

  window.saveShortcut = function() {
    if (editingIndex < 0 || editingIndex >= shortcuts.length) return;
    var label = labelInput.value.trim() || 'Shortcut ' + (editingIndex + 1);
    var url = urlInput.value.trim() || 'https://www.google.com';
    var img = imgInput.value.trim() || defaultShortcuts[editingIndex]?.img || '';
    shortcuts[editingIndex] = { label: label, url: url, img: img };
    saveShortcutsData();
    renderShortcuts();
    closeModal();
  };

  loadShortcuts();
};

// Main scramjet logic
var mainScript = function() {
  "use strict";

  var BASE_PATH = location.pathname.replace(/\/[^\/]*$/, "/");
  var swAllowedHostnames = ["localhost", "127.0.0.1"];

  var form = document.getElementById("sj-form");
  var address = document.getElementById("sj-address");
  var searchEngine = document.getElementById("sj-search-engine");
  var frameWrapper = document.getElementById("sj-frame-wrapper");
  var frameElement = document.getElementById("sj-frame");
  var frameUrl = document.getElementById("sj-frame-url");
  var error = document.getElementById("sj-error");
  var errorCode = document.getElementById("sj-error-code");
  var openNewTabBtn = document.getElementById("open-new-tab");
  var openAboutBlankBtn = document.getElementById("open-about-blank");
  var openBlobUrlBtn = document.getElementById("open-blob-url");
  var settingsButton = document.getElementById("settings-button");
  var settingsModal = document.getElementById("settings-modal");
  var closeSettings = document.getElementById("close-settings");
  var closeFrameLink = document.getElementById("close-frame-link");
  var wispInput = document.getElementById("wisp-server");

  function search(input, template) {
    try { return new URL(input).toString(); } catch (e) {}
    try {
      var url = new URL("http://" + input);
      if (url.hostname.includes(".")) return url.toString();
    } catch (e) {}
    if (
      input.includes("zaka") ||
      input.includes("zaka13") ||
      input.includes("zaka's games") ||
      input.includes("ign_zaka13")
    ) {
      alert("Why you searching my name up?");
      alert("lmfao");
    }
    return template.replace("%s", encodeURIComponent(input));
  }

  async function registerSW() {
    if (!navigator.serviceWorker) {
      if (location.protocol !== "https:" && !swAllowedHostnames.includes(location.hostname))
        throw new Error("Service workers cannot be registered without https.");
      throw new Error("Your browser doesn't support service workers.");
    }
    await navigator.serviceWorker.register(BASE_PATH + "sw.js", {
      scope: BASE_PATH,
      updateViaCache: "none",
    });
  }

  document.addEventListener("keydown", function(e) {
    if (e.ctrlKey && e.shiftKey && e.code === "KeyZ") {
      if (frameWrapper) frameWrapper.style.display = "none";
      if (closeFrameLink) closeFrameLink.style.display = "none";
    }
  });

  if (closeFrameLink) {
    closeFrameLink.addEventListener("click", function(e) {
      e.preventDefault();
      frameWrapper.style.display = "none";
      closeFrameLink.style.display = "none";
    });
  }

  function showErrorScreen(msg, details) {
    frameWrapper.style.display = "none";
    if (closeFrameLink) closeFrameLink.style.display = "none";
    error.textContent = msg || "something went wrong";
    errorCode.textContent = details || "";
  }

  var controller = null;
  var frame = null;
  var currentWisp = wispInput ? wispInput.value.trim() : "wss://wisp.zaka.qzz.io/wisp/";

  if (wispInput) {
    wispInput.addEventListener("change", function() {
      var val = this.value.trim();
      if (val) {
        currentWisp = val;
        if (controller) {
          controller = null;
          frame = null;
        }
      }
    });
  }

  async function initController() {
    controller = null;
    frame = null;

    var Controller = window.$scramjetController.Controller;
    var config = window.$scramjetController.config;

    config.scramjetPath = location.origin + BASE_PATH + "scj/scj.js";
    config.wasmPath = location.origin + BASE_PATH + "scj/scj.wasm";
    config.injectPath = location.origin + BASE_PATH + "controller/controller.inject.js";
    config.prefix = BASE_PATH + "~sj/";

    var transport = new window.LibcurlTransport.LibcurlClient({
      wisp: currentWisp,
    });

    controller = new Controller({
      serviceworker: navigator.serviceWorker.controller,
      transport: transport,
    });
    await controller.wait();

    frame = controller.createFrame(frameElement);
    if (!frame) throw new Error("createFrame returned null");
  }

  async function navigate(url) {
    if (!url.startsWith("http")) url = "https://" + url;
    if (!frame) await initController();
    await frame.go(url);
    frameWrapper.style.display = "flex";
    if (closeFrameLink) closeFrameLink.style.display = "inline";
    try {
      var displayUrl = new URL(url);
      frameUrl.textContent = displayUrl.hostname + displayUrl.pathname;
    } catch (e) {
      frameUrl.textContent = url;
    }
  }

  window.navigateTo = function(url) {
    address.value = url;
    form.dispatchEvent(new Event('submit'));
  };

  async function newTab() {
    if (address.value.trim() === "") {
      alert("Please type your search/URL");
      return;
    }
    var url = search(address.value, searchEngine.value);
    window.open(url, "_blank");
  }

  async function openAboutBlank() {
    if (address.value.trim() === "") {
      alert("Please type your search/URL");
      return;
    }
    var url = search(address.value, searchEngine.value);

    try {
      await registerSW();
    } catch (err) {
      error.textContent = "Failed to register service worker.";
      errorCode.textContent = err.toString();
      throw err;
    }

    if (!navigator.serviceWorker.controller) {
      await new Promise(function(resolve) {
        navigator.serviceWorker.addEventListener("controllerchange", resolve, { once: true });
      });
    }

    var aboutBlankWindow = window.open("about:blank", "_blank");
    if (aboutBlankWindow) {
      aboutBlankWindow.document.write('<html><head><title>' + url + '</title></head><body style="margin:0;padding:0;background:#000;overflow:hidden;"><iframe src="' + location.href + '?goto=' + encodeURIComponent(url) + '" style="width:100vw;height:100vh;border:none;"></iframe></body></html>');
      aboutBlankWindow.document.close();
    }
  }

  async function openBlobUrl() {
    if (address.value.trim() === "") {
      alert("Please type your search/URL");
      return;
    }
    var url = search(address.value, searchEngine.value);
    var blobDocument = '<html><head><title>' + url + '</title></head><body style="margin:0;padding:0;background:#000;overflow:hidden;"><iframe src="' + location.href + '?goto=' + encodeURIComponent(url) + '" style="width:100vw;height:100vh;border:none;"></iframe></body></html>';
    var blobUrl = URL.createObjectURL(new Blob([blobDocument], { type: "text/html" }));
    window.open(blobUrl, "_blank");
  }

  function closeSettingsPanel() {
    settingsModal.classList.remove("active");
  }

  form.addEventListener("submit", async function(event) {
    event.preventDefault();

    if (address.value.trim() === "") {
      alert("Please type your search/URL");
      return;
    }

    var url = search(address.value, searchEngine.value);

    try {
      await registerSW();
    } catch (err) {
      error.textContent = "Failed to register service worker.";
      errorCode.textContent = err.toString();
      throw err;
    }

    if (!navigator.serviceWorker.controller) {
      await new Promise(function(resolve) {
        navigator.serviceWorker.addEventListener("controllerchange", resolve, { once: true });
      });
    }

    try {
      await navigate(url);
    } catch (err) {
      showErrorScreen(err.message, err.stack);
    }
  });

  openNewTabBtn.addEventListener("click", newTab);
  openAboutBlankBtn.addEventListener("click", openAboutBlank);
  openBlobUrlBtn.addEventListener("click", openBlobUrl);
  settingsButton.addEventListener("click", function() { settingsModal.classList.add("active"); });
  closeSettings.addEventListener("click", closeSettingsPanel);
  settingsModal.addEventListener("click", function(event) {
    if (event.target === settingsModal) closeSettingsPanel();
  });

  var goto = new URL(location.href).searchParams.get("goto");
  if (goto) {
    history.replaceState(null, "", location.pathname);
    address.value = goto;
    registerSW()
      .then(function() {
        if (!navigator.serviceWorker.controller) {
          return new Promise(function(resolve) {
            navigator.serviceWorker.addEventListener("controllerchange", resolve, { once: true });
          });
        }
      })
      .then(function() { return navigate(goto); })
      .catch(function(err) { showErrorScreen(err.message, err.stack); });
  }

  window.newTab = newTab;
  window.openAboutBlank = openAboutBlank;
  window.openBlobUrl = openBlobUrl;
};

// Initialize all scripts
quoteScript();
shortcutScript();
mainScript();
//

